  1→/**
  2→ * BrowserView Manager
  3→ *
  4→ * Manages Electron BrowserViews for the agent browser automation feature.
  5→ * Uses native Electron BrowserView APIs for cross-platform web automation.
  6→ *
  7→ * Z-order strategy:
  8→ *   BrowserViews are currently added via contentView.addChildView(view)
  9→ *   which renders them on top of the main WebContents. The renderer hides
 10→ *   all views when dialogs/modals are open to prevent overlap issues.
 11→ *   Rendering behind the DOM via addChildView(view, 0) with a transparent
 12→ *   browser panel is tracked as a follow-up improvement.
 13→ *
 14→ * Each browser view gets:
 15→ * - A shared session partition for cookie persistence across tabs/restarts
 16→ * - A preload script for console capture + keyboard routing
 17→ * - Main-world polyfill injection (WebAuthn, local-network-access)
 18→ * - Event forwarding (page-load, title, url, navigation)
 19→ *
 20→ * Handler names match the snake_case names the renderer calls via invoke().
 21→ * Handlers prefixed "browser:" are invoked via the generic invoke() bridge
 22→ * (back, forward, createDetachedWindow, closeDetachedWindow).
 23→ */
 24→
 25→import { WebContentsView, BrowserWindow, ipcMain } from "electron";
 26→import { join } from "path";
 27→import { is } from "@electron-toolkit/utils";
 28→
 29→const views = new Map<string, WebContentsView>();
 30→const viewBounds = new Map<string, Electron.Rectangle>();
 31→
 32→/** Reference to the detached browser window (only one at a time) */
 33→let detachedWindow: BrowserWindow | null = null;
 34→
 35→/** Centralized main window lookup — avoids repeating getAllWindows()[0] in every handler */
 36→function getMainWindow(): BrowserWindow | undefined {
 37→  return (
 38→    BrowserWindow.getAllWindows().find((w) => w !== detachedWindow) ??
 39→    BrowserWindow.getAllWindows()[0]
 40→  );
 41→}
 42→
 43→// ---------------------------------------------------------------------------
 44→// Main-world polyfill scripts
 45→//
 46→// These are injected via view.webContents.executeJavaScript() on `dom-ready`
 47→// so they run in the page's main world. The preload's webFrame.executeJavaScript()
 48→// runs in the isolated world and cannot override page-visible APIs like
 49→// navigator.credentials or navigator.permissions.
 50→// ---------------------------------------------------------------------------
 51→
 52→const WEBAUTHN_POLYFILL_JS = `(function() {
 53→  if (typeof navigator === 'undefined' || !navigator.credentials) return;
 54→  if (navigator.credentials.__webAuthnPolyfillApplied) return;
 55→  navigator.credentials.__webAuthnPolyfillApplied = true;
 56→
 57→  function createNotSupportedError() {
 58→    return new DOMException('WebAuthn is not supported in the Deus browser. Click "Try another way" to use password login.', 'NotSupportedError');
 59→  }
 60→
 61→  var origCreate = navigator.credentials.create;
 62→  var origGet = navigator.credentials.get;
 63→
 64→  // Reject passkey/FIDO2 requests immediately so sites fall back to
 65→  // password login. Wrapping the original method with a 45s timeout
 66→  // just makes users wait — rejecting instantly shows the fallback UI.
 67→  navigator.credentials.create = function(options) {
 68→    if (options && options.publicKey) return Promise.reject(createNotSupportedError());
 69→    return origCreate ? origCreate.apply(navigator.credentials, arguments) : Promise.reject(createNotSupportedError());
 70→  };
 71→  navigator.credentials.get = function(options) {
 72→    if (options && options.publicKey) return Promise.reject(createNotSupportedError());
 73→    return origGet ? origGet.apply(navigator.credentials, arguments) : Promise.reject(createNotSupportedError());
 74→  };
 75→
 76→  if (typeof PublicKeyCredential !== 'undefined') {
 77→    PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable = function() {
 78→      return Promise.resolve(false);
 79→    };
 80→    if (typeof PublicKeyCredential.isConditionalMediationAvailable === 'function') {
 81→      PublicKeyCredential.isConditionalMediationAvailable = function() {
 82→        return Promise.resolve(false);
 83→      };
 84→    }
 85→  }
 86→})();`;
 87→
 88→const LOCAL_NETWORK_POLYFILL_JS = `(function() {
 89→  if (typeof navigator === 'undefined' || !navigator.permissions || !navigator.permissions.query) return;
 90→  if (navigator.permissions.__localNetworkPolyfillApplied) return;
 91→  navigator.permissions.__localNetworkPolyfillApplied = true;
 92→
 93→  var origQuery = navigator.permissions.query.bind(navigator.permissions);
 94→  navigator.permissions.query = function(descriptor) {
 95→    if (descriptor && (descriptor.name === 'local-network-access' || descriptor.name === 'local-network')) {
 96→      return Promise.resolve({
 97→        state: 'granted',
 98→        name: descriptor.name,
 99→        onchange: null,
100→        addEventListener: function() {},
101→        removeEventListener: function() {},
102→        dispatchEvent: function() { return true; }
103→      });
104→    }
105→    return origQuery(descriptor);
106→  };
107→})();`;
108→
109→const AUTH_DOMAINS = [
110→  ".okta.com",
111→  ".okta-emea.com",
112→  ".oktapreview.com",
113→  ".duosecurity.com",
114→  ".duo.com",
115→  ".login.microsoftonline.com",
116→  ".onelogin.com",
117→  ".auth0.com",
118→  ".pingidentity.com",
119→  ".pingone.com",
120→  ".rippling.com",
121→];
122→
123→export function registerBrowserViewHandlers(): void {
124→  // -------------------------------------------------------------------------
125→  // Create a new browser view
126→  // Renderer calls: invoke("create_browser_webview", { label, url, x, y, width, height, windowLabel })
127→  // -------------------------------------------------------------------------
128→
129→  ipcMain.handle(
130→    "create_browser_webview",
131→    (
132→      _e,
133→      {
134→        label,
135→        url,
136→        x,
137→        y,
138→        width,
139→        height,
140→      }: {
141→        label: string;
142→        url: string;
143→        x: number;
144→        y: number;
145→        width: number;
146→        height: number;
147→        windowLabel?: string;
148→      }
149→    ) => {
150→      const mainWindow = getMainWindow();
151→      if (!mainWindow) return;
152→
153→      // Clean up existing view with same label
154→      const existing = views.get(label);
155→      if (existing) {
156→        mainWindow.contentView.removeChildView(existing);
157→        (existing.webContents as any).destroy?.();
158→        views.delete(label);
159→      }
160→
161→      // getBoundingClientRect() returns CSS-pixel coordinates, but
162→      // WebContentsView.setBounds() operates in the window's native coordinate
163→      // space. When the user zooms the renderer (Cmd+/Cmd-), CSS pixels diverge
164→      // from window points by the zoom factor — multiply to correct.
165→      const zoomFactor = mainWindow.webContents.getZoomFactor();
166→      const bounds = {
167→        x: Math.round(x * zoomFactor),
168→        y: Math.round(y * zoomFactor),
169→        width: Math.round(Math.max(width * zoomFactor, 100)),
170→        height: Math.round(Math.max(height * zoomFactor, 100)),
171→      };
172→
173→      const view = new WebContentsView({
174→        webPreferences: {
175→          // Single shared partition — all tabs share cookies like a real browser.
176→          // Login once on localhost:3000, every tab sees it. Persists across restarts.
177→          partition: "persist:browser",
178→          contextIsolation: true,
179→          nodeIntegration: false,
180→          nodeIntegrationInSubFrames: false,
181→          sandbox: false, // ESM preload (.mjs) requires sandbox: false — TODO: convert to CJS
182→          webviewTag: false,
183→          navigateOnDragDrop: false,
184→          enableBlinkFeatures: "StandardizedBrowserZoom",
185→          preload: join(__dirname, "../preload/browser-preload.mjs"),
186→        },
187→      });
188→
189→      // Add as a child of contentView. Currently renders on top of main
190→      // WebContents (same as old BrowserView behavior). To render BEHIND
191→      // the DOM (like Cursor/VS Code), use addChildView(view, 0) and make
192→      // the browser panel area transparent — tracked as a follow-up.
193→      mainWindow.contentView.addChildView(view);
194→      view.setBounds(bounds);
195→      views.set(label, view);
196→
197→      // Register event listeners BEFORE loadURL to avoid race conditions.
198→      // loadURL() triggers loading events that must be captured.
199→      //
200→      // Event semantics:
201→      //   did-start-loading  — any frame starts (main + iframes/ads)
202→      //   did-stop-loading   — ALL frames finished (tab spinner stops)
203→      //   did-finish-load    — main frame only
204→      //   did-fail-load      — main frame navigation failure
205→      //
206→      // We use did-start-loading + did-stop-loading to match browser tab
207→      // spinner behavior. did-finish-load fires before subresources are
208→      // done, and did-start-loading fires for iframes too — using
209→      // did-stop-loading as "finished" ensures loading state clears once
210→      // everything is truly done (no stuck spinner from ad iframes).
211→      view.webContents.on("did-start-loading", () => {
212→        mainWindow.webContents.send("browser:page-load", {
213→          label,
214→          url: view.webContents.getURL(),
215→          event: "started",
216→        });
217→      });
218→
219→      view.webContents.on("did-stop-loading", () => {
220→        mainWindow.webContents.send("browser:page-load", {
221→          label,
222→          url: view.webContents.getURL(),
223→          event: "finished",
224→        });
225→      });
226→
227→      view.webContents.on(
228→        "did-fail-load",
229→        (_event, errorCode, errorDescription, _url, isMainFrame) => {
230→          // Only report main frame failures — subframe failures (ads, iframes)
231→          // shouldn't show as page-level errors.
232→          // ERR_ABORTED (-3) fires during redirects and canceled navigations — not a real failure.
233→          if (!isMainFrame || errorCode === -3) return;
234→          mainWindow.webContents.send("browser:page-load", {
235→            label,
236→            url: view.webContents.getURL(),
237→            event: "failed",
238→            error: { code: errorCode, description: errorDescription },
239→          });
240→        }
241→      );
242→
243→      view.webContents.on("page-title-updated", (_, title) => {
244→        mainWindow.webContents.send("browser:title-changed", { label, title });
245→      });
246→
247→      view.webContents.on("did-navigate", () => {
248→        mainWindow.webContents.send("browser:url-change", {
249→          label,
250→          url: view.webContents.getURL(),
251→        });
252→      });
253→
254→      view.webContents.on("did-navigate-in-page", () => {
255→        mainWindow.webContents.send("browser:url-change", {
256→          label,
257→          url: view.webContents.getURL(),
258→        });
259→      });
260→
261→      // TODO: Network request tracking — disabled until renderer listener is wired.
262→      // The events were being sent but nothing consumed them (wasted IPC traffic).
263→
264→      // Certificate error handling — only accept self-signed certs on localhost
265→      // in development mode. Production builds reject all cert errors.
266→      view.webContents.on("certificate-error", (event, _url, _error, _certificate, callback) => {
267→        if (is.dev) {
268→          try {
269→            const parsed = new URL(_url);
270→            if (parsed.hostname === "localhost" || parsed.hostname === "127.0.0.1") {
271→              event.preventDefault();
272→              callback(true);
273→              return;
274→            }
275→          } catch {
276→            // Malformed URL — fall through to reject
277→          }
278→        }
279→        callback(false);
280→      });
281→
282→      // Handle popups (window.open, target="_blank", OAuth flows).
283→      // Instead of opening in the system browser (which breaks OAuth callbacks),
284→      // forward to the renderer so it opens as a new browser tab in the IDE.
285→      // This matches how Cursor handles it — popup stays in-app, cookies are shared.
286→      view.webContents.setWindowOpenHandler(({ url: linkUrl, disposition }) => {
287→        try {
288→          const parsed = new URL(linkUrl);
289→          if (parsed.protocol === "http:" || parsed.protocol === "https:") {
290→            // Send to renderer to open as a new browser tab
291→            mainWindow.webContents.send("browser:new-tab-requested", {
292→              url: linkUrl,
293→              disposition, // "foreground-tab", "background-tab", "new-window"
294→              openerLabel: label,
295→            });
296→          }
297→        } catch {
298→          // Ignore malformed URLs
299→        }
300→        return { action: "deny" };
301→      });
302→
303→      // Handle messages from the browser preload (keyboard shortcuts + console)
304→      view.webContents.on("ipc-message", (_event, channel, ...args) => {
305→        if (channel === "browser:keyboard-shortcut") {
306→          const payload = args[0];
307→          if (!payload || typeof payload !== "object") return;
308→          const { shortcut } = payload as { shortcut: string };
309→          if (shortcut === "reload") {
310→            view.webContents.reload();
311→          } else if (shortcut === "focus-url-bar") {
312→            // Forward to renderer so the URL bar can be focused
313→            mainWindow.webContents.send("browser:keyboard-shortcut", { shortcut });
314→          }
315→        } else if (channel === "browser:console-message") {
316→          // Forward console messages from browser views to the renderer
317→          mainWindow.webContents.send("browser:console-message", args[0]);
318→        }
319→      });
320→
321→      // Inject polyfills into the page's main world.
322→      // WebAuthn must run BEFORE page scripts — use did-start-navigation so it
323→      // executes before any site JS checks PublicKeyCredential availability.
324→      // dom-ready is too late: Google's auth JS runs during parsing.
325→      view.webContents.on("did-start-navigation", (_event, _url, isInPlace, isMainFrame) => {
326→        if (!isMainFrame || isInPlace) return;
327→        // WebAuthn polyfill — immediate rejection for passkey/FIDO2 requests
328→        view.webContents.executeJavaScript(WEBAUTHN_POLYFILL_JS).catch(() => {});
329→      });
330→
331→      // Local network polyfill needs the final URL (after redirects), so use dom-ready
332→      view.webContents.on("dom-ready", () => {
333→        try {
334→          const pageUrl = view.webContents.getURL();
335→          const hostname = new URL(pageUrl).hostname.toLowerCase();
336→          if (AUTH_DOMAINS.some((d) => hostname === d.slice(1) || hostname.endsWith(d))) {
337→            view.webContents.executeJavaScript(LOCAL_NETWORK_POLYFILL_JS).catch(() => {});
338→          }
339→        } catch {
340→          /* malformed URL — skip polyfill */
341→        }
342→      });
343→
344→      // Start navigation AFTER all listeners are attached
345→      view.webContents.loadURL(url);
346→    }
347→  );
348→
349→  // -------------------------------------------------------------------------
350→  // Navigation
351→  // Renderer calls: invoke("navigate_browser_webview", { label, url })
352→  // -------------------------------------------------------------------------
353→
354→  ipcMain.handle(
355→    "navigate_browser_webview",
356→    (_e, { label, url }: { label: string; url: string }) => {
357→      views.get(label)?.webContents.loadURL(url);
358→    }
359→  );
360→
361→  // -------------------------------------------------------------------------
362→  // JavaScript evaluation (fire-and-forget)
363→  // Renderer calls: invoke("eval_browser_webview", { label, js })
364→  // Used by BrowserTab.tsx to inject automation scripts into the webview.
365→  // -------------------------------------------------------------------------
366→
367→  ipcMain.handle(
368→    "eval_browser_webview",
369→    async (_e, { label, js }: { label: string; js: string }) => {
370→      const view = views.get(label);
371→      if (!view) return null;
372→      try {
373→        return await view.webContents.executeJavaScript(js);
374→      } catch (err) {
375→        console.error(`[BrowserView] eval failed for "${label}":`, err);
376→        return null;
377→      }
378→    }
379→  );
380→
381→  // -------------------------------------------------------------------------
382→  // JavaScript evaluation (with result capture + timeout)
383→  // Renderer calls: invoke("eval_browser_webview_with_result", { label, js, timeout_ms })
384→  // Used by BrowserTab.tsx for console drain and inspect mode event drain.
385→  // -------------------------------------------------------------------------
386→
387→  ipcMain.handle(
388→    "eval_browser_webview_with_result",
389→    async (_e, { label, js, timeout_ms }: { label: string; js: string; timeout_ms?: number }) => {
390→      const view = views.get(label);
391→      if (!view) return null;
392→      try {
393→        const timeout = timeout_ms ?? 30_000;
394→        return await Promise.race([
395→          view.webContents.executeJavaScript(js),
396→          new Promise<never>((_, reject) =>
397→            setTimeout(() => reject(new Error("Eval timeout")), timeout)
398→          ),
399→        ]);
400→      } catch (err) {
401→        console.error(`[BrowserView] eval failed for "${label}":`, err);
402→        return null;
403→      }
404→    }
405→  );
406→
407→  // -------------------------------------------------------------------------
408→  // Screenshot
409→  // Renderer calls: invoke("screenshot_browser_webview", { label, x?, y?, width?, height? })
410→  // Supports optional crop rectangle; omit for full page capture.
411→  // -------------------------------------------------------------------------
412→
413→  ipcMain.handle(
414→    "screenshot_browser_webview",
415→    async (
416→      _e,
417→      {
418→        label,
419→        x,
420→        y,
421→        width,
422→        height,
423→      }: {
424→        label: string;
425→        x?: number;
426→        y?: number;
427→        width?: number;
428→        height?: number;
429→      }
430→    ) => {
431→      const view = views.get(label);
432→      if (!view) return null;
433→      try {
434→        let image;
435→        if (x !== undefined && y !== undefined && width !== undefined && height !== undefined) {
436→          image = await view.webContents.capturePage({
437→            x: Math.round(x),
438→            y: Math.round(y),
439→            width: Math.round(width),
440→            height: Math.round(height),
441→          });
442→        } else {
443→          image = await view.webContents.capturePage();
444→        }
445→        return image.toDataURL();
446→      } catch (err) {
447→        console.error(`[BrowserView] screenshot failed for "${label}":`, err);
448→        return null;
449→      }
450→    }
451→  );
452→
453→  // -------------------------------------------------------------------------
454→  // DevTools
455→  // Renderer calls: invoke("open_browser_devtools", { label })
456→  //                 invoke("close_browser_devtools", { label })
457→  // -------------------------------------------------------------------------
458→
459→  ipcMain.handle(
460→    "open_browser_devtools",
461→    (_e, { label, mode }: { label: string; mode?: "right" | "bottom" | "detach" | "undocked" }) => {
462→      views.get(label)?.webContents.openDevTools({ mode: mode ?? "bottom" });
463→    }
464→  );
465→
466→  ipcMain.handle("close_browser_devtools", (_e, { label }: { label: string }) => {
467→    const view = views.get(label);
468→    if (view?.webContents.isDevToolsOpened()) {
469→      view.webContents.closeDevTools();
470→    }
471→  });
472→
473→  // -------------------------------------------------------------------------
474→  // Bounds / visibility
475→  // Renderer calls: invoke("set_browser_webview_bounds", { label, x, y, width, height })
476→  //                 invoke("show_browser_webview", { label })
477→  //                 invoke("hide_browser_webview", { label })
478→  //                 invoke("close_browser_webview", { label })
479→  //                 invoke("reload_browser_webview", { label })
480→  // -------------------------------------------------------------------------
481→
482→  ipcMain.handle(
483→    "set_browser_webview_bounds",
484→    (
485→      _e,
486→      {
487→        label,
488→        x,
489→        y,
490→        width,
491→        height,
492→      }: {
493→        label: string;
494→        x: number;
495→        y: number;
496→        width: number;
497→        height: number;
498→      }
499→    ) => {
500→      // CSS-pixel → window-point conversion (see create_browser_webview comment)
501→      const mainWindow = getMainWindow();
502→      const zoomFactor = mainWindow?.webContents.getZoomFactor() ?? 1;
503→      const bounds = {
504→        x: Math.round(x * zoomFactor),
505→        y: Math.round(y * zoomFactor),
506→        width: Math.round(width * zoomFactor),
507→        height: Math.round(height * zoomFactor),
508→      };
509→      const view = views.get(label);
510→      if (view) {
511→        view.setBounds(bounds);
512→        // Also save to viewBounds so show() uses the latest position
513→        // (important when setBounds is called while the view is hidden/detached)
514→        viewBounds.set(label, bounds);
515→      }
516→    }
517→  );
518→
519→  ipcMain.handle("show_browser_webview", (_e, { label }: { label: string }) => {
520→    const mainWindow = getMainWindow();
521→    const view = views.get(label);
522→    if (mainWindow && view) {
523→      // Ensure view is in the contentView hierarchy
524→      const children = mainWindow.contentView.children;
525→      if (!children.includes(view)) {
526→        mainWindow.contentView.addChildView(view);
527→      }
528→      view.setVisible(true);
529→      const savedBounds = viewBounds.get(label);
530→      if (savedBounds) {
531→        view.setBounds(savedBounds);
532→      }
533→    }
534→  });
535→
536→  ipcMain.handle("hide_browser_webview", (_e, { label }: { label: string }) => {
537→    const view = views.get(label);
538→    if (view) {
539→      viewBounds.set(label, view.getBounds());
540→      view.setVisible(false);
541→    }
542→  });
543→
544→  // Hide ALL browser views at once — called when switching workspaces
545→  // or navigating to the welcome screen to ensure no stale native overlays.
546→  ipcMain.handle("hide_all_browser_webviews", () => {
547→    for (const [label, view] of views) {
548→      viewBounds.set(label, view.getBounds());
549→      view.setVisible(false);
550→    }
551→  });
552→
553→  ipcMain.handle("close_browser_webview", (_e, { label }: { label: string }) => {
554→    const view = views.get(label);
555→    if (!view) return;
556→    const mainWindow = getMainWindow();
557→    if (mainWindow) {
558→      mainWindow.contentView.removeChildView(view);
559→    }
560→    (view.webContents as any).destroy?.();
561→    views.delete(label);
562→    viewBounds.delete(label);
563→  });
564→
565→  ipcMain.handle("reload_browser_webview", (_e, { label }: { label: string }) => {
566→    views.get(label)?.webContents.reload();
567→  });
568→
569→  // -------------------------------------------------------------------------
570→  // View existence check (used by try-recall-before-create pattern)
571→  // -------------------------------------------------------------------------
572→
573→  ipcMain.handle("browser_view_exists", (_e, { label }: { label: string }) => {
574→    return views.has(label);
575→  });
576→
577→  // -------------------------------------------------------------------------
578→  // Back / Forward
579→  // -------------------------------------------------------------------------
580→
581→  ipcMain.handle("browser:back", (_e, { label }: { label: string }) => {
582→    const view = views.get(label);
583→    if (view?.webContents.canGoBack()) {
584→      view.webContents.goBack();
585→    }
586→  });
587→
588→  ipcMain.handle("browser:forward", (_e, { label }: { label: string }) => {
589→    const view = views.get(label);
590→    if (view?.webContents.canGoForward()) {
591→      view.webContents.goForward();
592→    }
593→  });
594→
595→  // -------------------------------------------------------------------------
596→  // Detached Browser Window
597→  // Renderer calls: invoke("browser:createDetachedWindow", { url, title, width, height, minWidth, minHeight })
598→  //                 invoke("browser:closeDetachedWindow")
599→  // -------------------------------------------------------------------------
600→
601→  ipcMain.handle(
602→    "browser:createDetachedWindow",
603→    (
604→      _e,
605→      {
606→        url,
607→        title,
608→        width,
609→        height,
610→        minWidth,
611→        minHeight,
612→      }: {
613→        url: string;
614→        title: string;
615→        width: number;
616→        height: number;
617→        minWidth?: number;
618→        minHeight?: number;
619→      }
620→    ) => {
621→      // Close existing detached window if any
622→      if (detachedWindow && !detachedWindow.isDestroyed()) {
623→        detachedWindow.close();
624→        detachedWindow = null;
625→      }
626→
627→      detachedWindow = new BrowserWindow({
628→        width,
629→        height,
630→        minWidth: minWidth ?? 600,
631→        minHeight: minHeight ?? 400,
632→        title,
633→        titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
634→        trafficLightPosition: { x: 16, y: 18 },
635→        webPreferences: {
636→          preload: join(__dirname, "../preload/index.mjs"),
637→          contextIsolation: true,
638→          nodeIntegration: false,
639→          sandbox: false, // ESM preload (index.mjs) requires sandbox: false
640→        },
641→      });
642→
643→      // Load the renderer app with the detached window URL
644→      if (is.dev && process.env.ELECTRON_RENDERER_URL) {
645→        detachedWindow.loadURL(`${process.env.ELECTRON_RENDERER_URL}${url}`);
646→      } else {
647→        detachedWindow.loadFile(join(__dirname, "../renderer/index.html"), {
648→          search: url.includes("?") ? url.split("?")[1] : "",
649→        });
650→      }
651→
652→      // Register close handler immediately after creation (before loadURL completes)
653→      // to prevent race conditions where the window closes before the listener is attached.
654→      detachedWindow.on("closed", () => {
655→        detachedWindow = null;
656→        const mainWindow = getMainWindow();
657→        if (mainWindow) {
658→          mainWindow.webContents.send("browser:detached-closed");
659→        }
660→      });
661→    }
662→  );
663→
664→  ipcMain.handle("browser:closeDetachedWindow", () => {
665→    if (detachedWindow && !detachedWindow.isDestroyed()) {
666→      detachedWindow.close();
667→      detachedWindow = null;
668→    }
669→  });
670→}
671→
672→/**
673→ * Clean up all browser views. Called on app quit.
674→ */
675→export function destroyAllBrowserViews(): void {
676→  const mainWindow = getMainWindow();
677→  for (const [, view] of views) {
678→    if (mainWindow) {
679→      mainWindow.contentView.removeChildView(view);
680→    }
681→    (view.webContents as any).destroy?.();
682→  }
683→  views.clear();
684→  viewBounds.clear();
685→
686→  if (detachedWindow && !detachedWindow.isDestroyed()) {
687→    detachedWindow.close();
688→    detachedWindow = null;
689→  }
690→}
