  1→// Browser automation tools powered by agent-browser CLI.
  2→// Each tool executes agent-browser commands via CDP (Chrome DevTools Protocol).
  3→// The daemon auto-starts on first use per session.
  4→//
  5→// Key features:
  6→// - Coordinate return: click/type/hover return element bounding boxes for screen recording
  7→// - Batch mode: BrowserBatchActions executes multiple commands in one round-trip
  8→// - Snapshot filtering: interactive-only, compact, depth-limited, CSS-scoped
  9→// - Wait modes: text, networkIdle, elementVisible, elementGone
 10→
 11→import { tool } from "@anthropic-ai/claude-agent-sdk";
 12→import type { SdkMcpToolDefinition } from "@anthropic-ai/claude-agent-sdk";
 13→import { z } from "zod";
 14→import { writeFileSync, mkdirSync, existsSync, readFileSync, unlinkSync } from "fs";
 15→import { join } from "path";
 16→import { homedir, tmpdir } from "os";
 17→import { getErrorMessage } from "@shared/lib/errors";
 18→import {
 19→  execAgentBrowser,
 20→  execWithSnapshot,
 21→  executeBatch,
 22→  getSnapshot,
 23→  type ElementBox,
 24→} from "./agent-browser-client";
 25→
 26→// ============================================================================
 27→// Snapshot file-based fallback constants
 28→// ============================================================================
 29→
 30→const SNAPSHOT_SIZE_THRESHOLD = 25 * 1024; // 25 KB for action tools
 31→const SNAPSHOT_SIZE_THRESHOLD_LARGE = 200 * 1024; // 200 KB for BrowserSnapshot
 32→const PREVIEW_LINE_COUNT = 50;
 33→const BROWSER_LOGS_DIR = join(homedir(), ".deus", "browser-logs");
 34→
 35→// ============================================================================
 36→// Shared response helpers
 37→// ============================================================================
 38→
 39→/** Wrap a tool handler with standard [browser] logging and error catch */
 40→function withBrowserTool<TArgs>(
 41→  name: string,
 42→  sessionId: string,
 43→  logExtra: (args: TArgs) => string,
 44→  fn: (args: TArgs) => Promise<{ content: Array<{ type: string; [key: string]: unknown }> }>
 45→): (args: TArgs) => Promise<{ content: Array<{ type: string; [key: string]: unknown }> }> {
 46→  return async (args: TArgs) => {
 47→    const extra = logExtra(args);
 48→    console.log(`[browser] ${name} invoked for session ${sessionId}${extra ? `: ${extra}` : ""}`);
 49→    try {
 50→      return await fn(args);
 51→    } catch (err: unknown) {
 52→      return textResult(`Browser not available: ${getErrorMessage(err)}`);
 53→    }
 54→  };
 55→}
 56→
 57→/** Build a single-text-block tool result */
 58→function textResult(text: string): { content: [{ type: "text"; text: string }] } {
 59→  return { content: [{ type: "text", text }] };
 60→}
 61→
 62→/** Redact sensitive arguments (passwords, tokens) from batch action summaries */
 63→function summarizeBatchAction(action: string[]): string {
 64→  const [command, firstArg] = action;
 65→  if (command === "fill" || command === "type") {
 66→    return [command, firstArg ?? "<?>", "<redacted>"].join(" ");
 67→  }
 68→  return action.join(" ");
 69→}
 70→
 71→/**
 72→ * Format a snapshot response with file-based fallback for large snapshots.
 73→ * Optionally includes element bounding box for screen recording.
 74→ */
 75→function formatSnapshotResponse(
 76→  action: string,
 77→  snapshot: string | undefined,
 78→  pageUrl?: string,
 79→  pageTitle?: string,
 80→  detailLines?: string[],
 81→  sizeThreshold: number = SNAPSHOT_SIZE_THRESHOLD,
 82→  elementBox?: ElementBox | null
 83→): string {
 84→  const sections: string[] = [];
 85→
 86→  sections.push(`### Action: ${action}`);
 87→  if (detailLines && detailLines.length > 0) {
 88→    for (const line of detailLines) {
 89→      sections.push(`- ${line}`);
 90→    }
 91→  }
 92→
 93→  if (elementBox) {
 94→    const cx = Math.round(elementBox.x + elementBox.width / 2);
 95→    const cy = Math.round(elementBox.y + elementBox.height / 2);
 96→    sections.push("");
 97→    sections.push("### Element");
 98→    sections.push(
 99→      `- Bounding box: x=${Math.round(elementBox.x)} y=${Math.round(elementBox.y)} w=${Math.round(elementBox.width)} h=${Math.round(elementBox.height)}`
100→    );
101→    sections.push(`- Center: (${cx}, ${cy})`);
102→  }
103→
104→  sections.push("");
105→  sections.push("### Page state");
106→  if (pageUrl) sections.push(`- Page URL: ${pageUrl}`);
107→  if (pageTitle) sections.push(`- Page Title: ${pageTitle}`);
108→
109→  if (!snapshot) {
110→    sections.push("- Page Snapshot: (not available)");
111→    return sections.join("\n");
112→  }
113→
114→  const snapshotBytes = Buffer.byteLength(snapshot, "utf-8");
115→  const snapshotLines = snapshot.split("\n");
116→
117→  if (snapshotBytes <= sizeThreshold) {
118→    sections.push(`- Page Snapshot (${snapshotLines.length} lines)`);
119→    sections.push("");
120→    sections.push(snapshot);
121→  } else {
122→    let filePath: string | null = null;
123→    try {
124→      if (!existsSync(BROWSER_LOGS_DIR)) {
125→        mkdirSync(BROWSER_LOGS_DIR, { recursive: true });
126→      }
127→      const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
128→      filePath = join(BROWSER_LOGS_DIR, `snapshot-${timestamp}.log`);
129→      writeFileSync(filePath, snapshot, "utf-8");
130→    } catch (err: unknown) {
131→      console.warn(`[browser] Failed to write snapshot file: ${getErrorMessage(err)}`);
132→    }
133→
134→    if (filePath) {
135→      sections.push(
136→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) written to file`
137→      );
138→      sections.push(`- Snapshot File: ${filePath}`);
139→      sections.push(`- Preview (first ${PREVIEW_LINE_COUNT} lines):`);
140→      sections.push("");
141→      sections.push(snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n"));
142→    } else {
143→      sections.push(
144→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) — truncated inline`
145→      );
146→      sections.push("");
147→      sections.push(snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n"));
148→    }
149→
150→    const remaining = snapshotLines.length - PREVIEW_LINE_COUNT;
151→    if (remaining > 0) {
152→      sections.push("");
153→      sections.push(
154→        filePath
155→          ? `... (${remaining} more lines in file)`
156→          : `... (${remaining} more lines truncated)`
157→      );
158→    }
159→  }
160→
161→  return sections.join("\n");
162→}
