531→- ["wait", "--text", "Done"] — wait for text
532→- ["hover", "@e2"] — hover element
533→- ["select", "@e4", "option1"] — select dropdown
534→
535→Example — fill and submit a login form:
536→  actions: [["fill", "@e1", "user@example.com"], ["fill", "@e2", "password"], ["click", "@e3"]]
537→
538→Returns a page snapshot after all actions complete.`,
539→      {
540→        actions: z
541→          .array(z.array(z.string()))
542→          .describe("Array of agent-browser commands. Each command is an array of strings."),
543→        bail: z
544→          .boolean()
545→          .optional()
546→          .describe("Stop on first error (default: false). Remaining actions are skipped."),
547→      },
548→      withBrowserTool(
