551→        (args) => `${args.actions.length} actions`,
552→        async (args) => {
553→          const result = await executeBatch(sessionId, args.actions, {
554→            bail: args.bail,
555→            timeoutMs: 60_000,
556→          });
557→
558→          if (!result.success) {
559→            return textResult(`Batch failed: ${result.error || "Unknown error"}`);
560→          }
561→
562→          const batchData = result.data?.results as Array<Record<string, unknown>> | undefined;
563→          const failures: string[] = [];
564→          if (Array.isArray(batchData)) {
565→            batchData.forEach((r, i) => {
566→              if (r && r.success === false) {
567→                failures.push(
568→                  `Action ${i + 1} (${summarizeBatchAction(args.actions[i] ?? [])}): ${r.error ?? "failed"}`
569→                );
570→              }
571→            });
572→          }
573→
574→          const snap = await getSnapshot(sessionId);
575→          if (snap.error) {
576→            return textResult(`Batch executed but snapshot failed: ${snap.error}`);
577→          }
578→          const actionSummary = args.actions
579→            .slice(0, 10)
580→            .map((a) => summarizeBatchAction(a))
581→            .join(", ");
582→          const details = [
583→            `Actions executed: ${args.actions.length}`,
584→            `Commands: ${actionSummary}${args.actions.length > 10 ? ` ... (+${args.actions.length - 10} more)` : ""}`,
585→          ];
586→
587→          if (failures.length > 0) {
588→            details.push(`Failures: ${failures.length}`);
589→            details.push(...failures.slice(0, 5));
590→            if (failures.length > 5) details.push(`... (+${failures.length - 5} more)`);
591→          }
592→
593→          return textResult(
594→            formatSnapshotResponse("batch", snap.snapshot, snap.url, snap.title, details)
595→          );
596→        }
597→      )
598→    ),
