  1→// Thin wrapper around the agent-browser CLI.
  2→// Executes commands via child_process and parses JSON responses.
  3→// The daemon auto-starts on the first command per session and maintains
  4→// browser state (refs, cookies, DOM) across calls.
  5→
  6→import { execFile, spawn } from "child_process";
  7→import { dirname, join } from "path";
  8→
  9→export interface AgentBrowserResult {
 10→  success: boolean;
 11→  data: Record<string, unknown> | null;
 12→  error: string | null;
 13→}
 14→
 15→export interface ElementBox {
 16→  x: number;
 17→  y: number;
 18→  width: number;
 19→  height: number;
 20→}
 21→
 22→// Resolve the binary once at module load.
 23→// The npm package has a Node.js wrapper at bin/agent-browser.js that selects
 24→// the correct platform binary. We resolve it relative to the package directory
 25→// since the package has no "main" field (require.resolve would throw).
 26→// Note: agent-server is bundled to CJS, so require.resolve is available.
 27→const BINARY = (() => {
 28→  try {
 29→    const pkgDir = dirname(require.resolve("agent-browser/package.json"));
 30→    return join(pkgDir, "bin", "agent-browser.js");
 31→  } catch {
 32→    return "agent-browser"; // fallback to PATH
 33→  }
 34→})();
 35→
 36→const DEFAULT_TIMEOUT_MS = 35_000;
 37→
 38→/**
 39→ * When CDP_PORT is set (Electron desktop mode), agent-browser connects to the
 40→ * IDE's own BrowserView via Chrome DevTools Protocol instead of spawning a
 41→ * separate Chrome process. This means:
 42→ * - Agent and user see the same browser (shared cookies, real-time visibility)
 43→ * - No separate Chrome daemon to manage
 44→ * - `--cdp <port>` is prepended to all agent-browser commands
 45→ */
 46→const CDP_PORT = process.env.CDP_PORT;
 47→
 48→/** Build final args with optional CDP prefix */
 49→function buildArgs(args: string[]): string[] {
 50→  return CDP_PORT ? ["--cdp", CDP_PORT, ...args] : args;
 51→}
 52→
 53→/** Build env for agent-browser subprocess */
 54→function buildEnv(sessionId: string): NodeJS.ProcessEnv {
 55→  return {
 56→    ...process.env,
 57→    AGENT_BROWSER_SESSION: sessionId,
 58→    AGENT_BROWSER_HEADED: "1",
 59→  };
 60→}
 61→
 62→/** Parse the last JSON object from stdout (agent-browser may print status lines before JSON) */
 63→function parseJsonFromOutput(output: string): AgentBrowserResult | null {
 64→  if (!output) return null;
 65→  const lines = output.split("\n");
 66→  for (let i = lines.length - 1; i >= 0; i--) {
 67→    const line = lines[i].trim();
 68→    if (line.startsWith("{") || line.startsWith("[")) {
 69→      try {
 70→        const parsed = JSON.parse(line);
 71→        if (Array.isArray(parsed)) {
 72→          return { success: true, data: { results: parsed }, error: null };
 73→        }
 74→        const error =
 75→          typeof parsed.error === "string" && parsed.error.length > 0 ? parsed.error : null;
 76→        return {
 77→          success: parsed.success === false ? false : error == null,
 78→          data: parsed.data ?? parsed,
 79→          error,
 80→        };
 81→      } catch {
 82→        continue;
 83→      }
 84→    }
 85→  }
 86→  return null;
 87→}
 88→
 89→/**
 90→ * Execute an agent-browser command for a given session.
 91→ */
 92→export async function execAgentBrowser(
 93→  sessionId: string,
 94→  args: string[],
 95→  timeoutMs = DEFAULT_TIMEOUT_MS
 96→): Promise<AgentBrowserResult> {
 97→  const finalArgs = buildArgs(args);
 98→  const env = buildEnv(sessionId);
 99→
100→  return new Promise<AgentBrowserResult>((resolve, reject) => {
101→    const child = execFile(
102→      BINARY,
103→      finalArgs,
104→      { env, timeout: timeoutMs, maxBuffer: 10 * 1024 * 1024 },
105→      (error, stdout, stderr) => {
106→        const output = stdout.trim();
107→        const parsed = parseJsonFromOutput(output);
108→        if (parsed) {
109→          resolve(parsed);
110→          return;
111→        }
112→
113→        if (error) {
114→          resolve({
115→            success: false,
116→            data: output ? { text: output } : null,
117→            error: stderr || error.message,
118→          });
119→          return;
120→        }
121→
122→        if (!output) {
123→          resolve({ success: true, data: null, error: null });
124→          return;
125→        }
126→
127→        resolve({ success: true, data: { text: output }, error: null });
128→      }
129→    );
130→
131→    child.on("error", (err) => reject(err));
132→  });
133→}
134→
135→/**
136→ * Execute an agent-browser command with stdin input (used for batch mode).
137→ * Uses spawn instead of execFile to pipe stdin data.
138→ */
139→export async function execAgentBrowserWithStdin(
140→  sessionId: string,
141→  args: string[],
142→  stdinData: string,
143→  timeoutMs = DEFAULT_TIMEOUT_MS
144→): Promise<AgentBrowserResult> {
145→  const finalArgs = buildArgs(args);
146→  const env = buildEnv(sessionId);
147→
148→  return new Promise<AgentBrowserResult>((resolve, reject) => {
149→    const child = spawn(BINARY, finalArgs, {
150→      env,
151→      stdio: ["pipe", "pipe", "pipe"],
152→    });
153→
154→    const MAX_OUTPUT_BYTES = 10 * 1024 * 1024;
155→    let stdout = "";
156→    let stderr = "";
157→    let outputBytes = 0;
158→    let settled = false;
159→
160→    function abort(error: string): void {
161→      if (settled) return;
162→      settled = true;
163→      clearTimeout(timer);
164→      child.kill("SIGTERM");
165→      resolve({ success: false, data: null, error });
166→    }
167→
168→    const timer = setTimeout(() => abort("Batch timed out"), timeoutMs);
169→
170→    child.stdout.on("data", (chunk: Buffer) => {
171→      outputBytes += chunk.length;
172→      if (outputBytes > MAX_OUTPUT_BYTES) return abort("Batch output exceeded 10MB");
173→      stdout += chunk.toString();
174→    });
175→    child.stderr.on("data", (chunk: Buffer) => {
176→      outputBytes += chunk.length;
177→      if (outputBytes > MAX_OUTPUT_BYTES) return abort("Batch output exceeded 10MB");
178→      stderr += chunk.toString();
179→    });
180→
181→    child.on("close", (code) => {
182→      if (settled) return;
183→      settled = true;
184→      clearTimeout(timer);
185→
186→      const output = stdout.trim();
187→      const parsed = parseJsonFromOutput(output);
188→      if (parsed) {
189→        resolve(parsed);
190→        return;
191→      }
192→
193→      if (code !== 0) {
194→        resolve({
195→          success: false,
196→          data: output ? { text: output } : null,
197→          error: stderr || `Process exited with code ${code}`,
198→        });
199→        return;
200→      }
201→
202→      resolve({ success: true, data: output ? { text: output } : null, error: null });
203→    });
204→
205→    child.on("error", (err) => {
206→      if (!settled) {
207→        settled = true;
208→        clearTimeout(timer);
209→        reject(err);
210→      }
211→    });
212→
213→    // Write stdin data and close
214→    child.stdin.write(stdinData);
215→    child.stdin.end();
216→  });
217→}
218→
219→/**
220→ * Get an element's bounding box (best-effort, returns null on failure).
221→ * Used for screen recording cursor animation.
222→ */
223→export async function getElementBox(sessionId: string, ref: string): Promise<ElementBox | null> {
224→  try {
225→    const result = await execAgentBrowser(sessionId, ["get", "box", ref, "--json"], 5_000);
226→    if (!result.success || !result.data) return null;
227→    const d = result.data;
228→    if (typeof d.x === "number" && typeof d.y === "number") {
229→      return {
230→        x: d.x as number,
231→        y: d.y as number,
232→        width: (d.width as number) || 0,
233→        height: (d.height as number) || 0,
234→      };
235→    }
236→    return null;
237→  } catch {
238→    return null;
239→  }
240→}
