242→/**
243→ * Execute a batch of agent-browser commands in a single call.
244→ * Uses stdin-based batch mode for 10x fewer round-trips.
245→ *
246→ * Example: executeBatch(sessionId, [["click", "@e1"], ["fill", "@e3", "hello"]])
247→ */
248→export async function executeBatch(
249→  sessionId: string,
250→  commands: string[][],
251→  options?: { bail?: boolean; timeoutMs?: number }
252→): Promise<AgentBrowserResult> {
253→  const args = ["batch", "--json"];
254→  if (options?.bail) args.push("--bail");
255→  const stdinData = JSON.stringify(commands);
256→  return execAgentBrowserWithStdin(
257→    sessionId,
258→    args,
259→    stdinData,
260→    options?.timeoutMs ?? DEFAULT_TIMEOUT_MS
261→  );
262→}
