264→/**
265→ * Execute an agent-browser command and return snapshot + metadata.
266→ * Optionally fetches element bounding box for screen recording.
267→ *
268→ * Performance: snapshot, url, title, and box are fetched concurrently
269→ * via Promise.all (saves ~150ms vs sequential).
270→ */
271→export async function execWithSnapshot(
272→  sessionId: string,
273→  args: string[],
274→  timeoutMs?: number,
275→  interactedRef?: string
276→): Promise<{
277→  snapshot?: string;
278→  url?: string;
279→  title?: string;
280→  error?: string;
281→  elementBox?: ElementBox | null;
282→}> {
283→  try {
284→    const result = await execAgentBrowser(sessionId, args, timeoutMs);
285→    if (!result.success) {
286→      return { error: result.error || "Unknown error" };
287→    }
288→
289→    // Fetch metadata concurrently — all are independent read-only queries
290→    const [snapResult, urlResult, titleResult, box] = await Promise.all([
291→      execAgentBrowser(sessionId, ["snapshot", "--json"], timeoutMs),
292→      execAgentBrowser(sessionId, ["get", "url", "--json"]).catch(() => null),
293→      execAgentBrowser(sessionId, ["get", "title", "--json"]).catch(() => null),
294→      interactedRef ? getElementBox(sessionId, interactedRef) : Promise.resolve(null),
295→    ]);
296→
297→    if (!snapResult.success) {
298→      return { error: `Action succeeded but snapshot failed: ${snapResult.error || "unknown"}` };
299→    }
300→
301→    return {
302→      snapshot: (snapResult.data?.snapshot as string) || (snapResult.data?.text as string),
303→      url: (urlResult?.data?.url as string) || (urlResult?.data?.text as string),
304→      title: (titleResult?.data?.title as string) || (titleResult?.data?.text as string),
305→      elementBox: box,
306→    };
307→  } catch (err: unknown) {
308→    return { error: err instanceof Error ? err.message : String(err) };
309→  }
310→}
