312→/**
313→ * Get a snapshot with URL and title.
314→ * Supports optional filtering flags for smaller, more focused snapshots.
315→ */
316→export async function getSnapshot(
317→  sessionId: string,
318→  timeoutMs?: number,
319→  options?: {
320→    interactive?: boolean;
321→    compact?: boolean;
322→    depth?: number;
323→    selector?: string;
324→  }
325→): Promise<{ snapshot?: string; url?: string; title?: string; error?: string }> {
326→  try {
327→    const snapArgs = ["snapshot", "--json"];
328→    if (options?.interactive) snapArgs.push("-i");
329→    if (options?.compact) snapArgs.push("-c");
330→    if (options?.depth !== undefined) snapArgs.push("-d", String(options.depth));
331→    if (options?.selector) snapArgs.push("-s", options.selector);
332→
333→    const [snapResult, urlResult, titleResult] = await Promise.all([
334→      execAgentBrowser(sessionId, snapArgs, timeoutMs),
335→      execAgentBrowser(sessionId, ["get", "url", "--json"]).catch(() => null),
336→      execAgentBrowser(sessionId, ["get", "title", "--json"]).catch(() => null),
337→    ]);
338→
339→    if (!snapResult.success) {
340→      return { error: snapResult.error || "Snapshot failed" };
341→    }
342→
343→    return {
344→      snapshot: (snapResult.data?.snapshot as string) || (snapResult.data?.text as string),
345→      url: (urlResult?.data?.url as string) || (urlResult?.data?.text as string),
346→      title: (titleResult?.data?.title as string) || (titleResult?.data?.text as string),
347→    };
348→  } catch (err: unknown) {
349→    return { error: err instanceof Error ? err.message : String(err) };
350→  }
351→}
