 45→/** Data emitted when user selects an element in inspect mode */
 46→export interface ElementSelectedEvent {
 47→  type: "element-selected" | "area-selected";
 48→  ref?: string;
 49→  /** "local" = own dev server (localhost), "external" = any other website */
 50→  context?: "local" | "external";
 51→  element?: {
 52→    tagName: string;
 53→    id?: string;
 54→    className?: string;
 55→    innerText?: string;
 56→    path: string;
 57→    rect: { top: number; left: number; width: number; height: number };
 58→    /** Context-aware CSS: var() tokens for local, visual props for external */
 59→    styles: Record<string, string>;
 60→    /** Serialized React props — primitives only (variant, size, disabled, etc.) */
 61→    props?: Record<string, string>;
 62→    /** Whitelisted HTML attributes (data-testid, href, type, role, aria-label, etc.) */
 63→    attributes?: Record<string, string>;
 64→    /** Shallow innerHTML capped at 500 chars — shows element structure */
 65→    innerHTML?: string;
 66→  };
