 77→/** Imperative methods exposed by BrowserTab via forwardRef */
 78→export interface BrowserTabHandle {
 79→  navigateToUrl: (url: string) => void;
 80→  /** Native session history back — preserves scroll/form state */
 81→  goBack: () => void;
 82→  /** Native session history forward — preserves scroll/form state */
 83→  goForward: () => void;
 84→  reload: () => void;
 85→  injectAutomation: () => Promise<void>;
 86→  toggleElementSelector: () => void;
 87→}
 88→
 89→/** Extract a readable title from a URL (domain or localhost:port) */
 90→export function deriveTitleFromUrl(url: string): string {
 91→  if (!url) return "New Tab";
 92→  try {
 93→    const parsed = new URL(url);
 94→    if (parsed.hostname === "localhost") {
 95→      return `localhost${parsed.port ? ":" + parsed.port : ""}`;
 96→    }
 97→    return parsed.hostname.replace(/^www\./, "");
 98→  } catch {
 99→    return "New Tab";
100→  }
101→}
102→
103→/** Create a fresh browser tab with default state.
104→ *  When workspaceId is provided, scopes the webview label to prevent
105→ *  collisions across workspaces. */
106→export function createBrowserTab(workspaceId?: string | null): BrowserTabState {
107→  const rand = Math.random().toString(36).slice(2, 6);
108→  const id = workspaceId
109→    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
110→    : `browser-tab-${Date.now()}-${rand}`;
111→  return {
112→    id,
113→    webviewLabel: id,
114→    title: "New Tab",
115→    url: "",
116→    currentUrl: "",
117→    history: [],
118→    historyIndex: -1,
119→    loading: false,
120→    error: null,
121→    injected: false,
122→    injectionFailed: false,
123→    selectorActive: false,
124→    devtoolsOpen: false,
125→    consoleLogs: [],
126→  };
127→}
128→
129→/** Hydrate a PersistedBrowserTab into a full BrowserTabState with
130→ *  ephemeral defaults (loading, history, consoleLogs, etc.) */
131→export function hydratePersistedTab(persisted: PersistedBrowserTab): BrowserTabState {
132→  // Use persisted.id as a stable webview label — same tab always maps to the
133→  // same native view. This enables view parking: parked views can be recalled
134→  // by label without creating a new native WebContentsView.
135→  return {
136→    id: persisted.id,
137→    webviewLabel: persisted.id,
138→    title: persisted.title || deriveTitleFromUrl(persisted.url),
139→    url: persisted.url,
140→    currentUrl: persisted.url,
141→    history: persisted.url ? [persisted.url] : [],
142→    historyIndex: persisted.url ? 0 : -1,
143→    loading: false,
144→    error: null,
145→    injected: false,
146→    injectionFailed: false,
147→    selectorActive: false,
148→    devtoolsOpen: false,
149→    consoleLogs: [],
150→  };
151→}
