  1→/**
  2→ * BrowserTab — native Electron BrowserView for one browser tab.
  3→ *
  4→ * Architecture: Renders a placeholder <div> and measures its bounds via
  5→ * ResizeObserver. Tells the main process to create/position a native BrowserView there.
  6→ * Unlike iframes, native BrowserViews bypass X-Frame-Options so any URL loads.
  7→ *
  8→ * All tabs stack via CSS Grid ([grid-area:1/1]) in the parent container.
  9→ * The native BrowserView floats above the DOM; overlays only show when view is hidden.
 10→ *
 11→ * Communication channels (each concern gets its own reliable path):
 12→ *   - IPC events: page-load, title-changed, url-change (push from Electron webContents)
 13→ *   - executeJavaScript: console drain + inspect event drain (pull from React)
 14→ *
 15→ * SPA navigation: pushState/replaceState patches in the init script fire
 16→ * browser:url-change events so the URL bar stays current.
 17→ */
 18→
 19→import {
 20→  useRef,
 21→  useState,
 22→  useEffect,
 23→  useLayoutEffect,
 24→  useCallback,
 25→  useImperativeHandle,
 26→  forwardRef,
 27→} from "react";
 28→import { match } from "ts-pattern";
 29→import { Button } from "@/components/ui/button";
 30→import { AlertCircle, Loader2, Globe } from "lucide-react";
 31→import { native } from "@/platform";
 32→import { BROWSER_PAGE_LOAD, BROWSER_TITLE_CHANGED, BROWSER_URL_CHANGE } from "@shared/events";
 33→import { getErrorMessage } from "@shared/lib/errors";
 34→import type { BrowserTabState, BrowserTabHandle, ConsoleLog, ElementSelectedEvent } from "../types";
 35→import { deriveTitleFromUrl } from "../types";
 36→import {
 37→  INSPECT_MODE_SETUP,
 38→  INSPECT_MODE_ENABLE,
 39→  INSPECT_MODE_DISABLE,
 40→  INSPECT_MODE_DRAIN_EVENTS,
 41→  INSPECT_MODE_VERIFY,
 42→} from "../automation/inspect-mode";
 43→import { VISUAL_EFFECTS_SETUP } from "../automation/visual-effects";
 44→
 45→/** How often to drain console logs from the webview (ms) */
 46→const CONSOLE_DRAIN_INTERVAL_MS = 1500;
 47→/** How often to drain inspect-mode events from the webview (ms) */
 48→const INSPECT_DRAIN_INTERVAL_MS = 200;
 49→
 50→interface BrowserTabProps {
 51→  tab: BrowserTabState;
 52→  /** Update tab state in the parent — (tabId, updates) */
 53→  onUpdateTab: (tabId: string, updates: Partial<BrowserTabState>) => void;
 54→  /** Add a log line to the tab's console — (tabId, level, message) */
 55→  onAddLog: (tabId: string, level: ConsoleLog["level"], message: string) => void;
 56→  /** Whether this tab is the active (visible) tab */
 57→  visible: boolean;
 58→  /** Callback when user selects an element in inspect mode */
 59→  onElementSelected?: (tabId: string, event: ElementSelectedEvent) => void;
 60→  /** Which Electron window to create child BrowserViews in. Defaults to "main". */
 61→  windowLabel?: string;
 62→  /** When true, the browser container is constrained to mobile width (390px).
 63→   *  Used to trigger a bounds sync — mx-auto centering shifts x-offset
 64→   *  and ResizeObserver may not catch position-only changes. */
 65→  mobileView?: boolean;
 66→}
 67→
 68→export const BrowserTab = forwardRef<BrowserTabHandle, BrowserTabProps>(function BrowserTab(
 69→  { tab, onUpdateTab, onAddLog, visible, onElementSelected, windowLabel, mobileView },
 70→  ref
 71→) {
 72→  const placeholderRef = useRef<HTMLDivElement>(null);
 73→  // Ref = source of truth for imperative callbacks (always fresh)
 74→  const webviewCreatedRef = useRef(false);
 75→  // State = triggers effects when webview is ready
 76→  const [webviewReady, setWebviewReady] = useState(false);
 77→  // Track whether first page load completed (show overlay only during initial load)
 78→  const [hasLoaded, setHasLoaded] = useState(false);
 79→  // Brief "completing" state for loading bar finish animation (fill → fade)
 80→  const [completingLoad, setCompletingLoad] = useState(false);
 81→  const completingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 82→  // Guard against unmount during async webview creation
 83→  const mountedRef = useRef(true);
 84→  // Debounce bounds sync to one per animation frame
 85→  const rafRef = useRef(0);
 86→  // Track whether automation scripts (inspect mode + visual effects) have been injected
 87→  const automationInjectedRef = useRef(false);
 88→  // Ref to latest tab state — used in event handlers to read current history
 89→  const tabRef = useRef(tab);
 90→  tabRef.current = tab;
 91→  // Guard: suppress history push during back/forward navigation
 92→  // (did-navigate fires for loadURL too, which would double-push)
 93→  const suppressHistoryPushRef = useRef(false);
 94→  // Stable ref for onElementSelected callback (used by the inspect drain loop)
 95→  const onElementSelectedRef = useRef(onElementSelected);
 96→  onElementSelectedRef.current = onElementSelected;
 97→  // Track previous mobileView value to detect actual toggles (vs initial mount)
 98→  const prevMobileViewRef = useRef(mobileView);
 99→
100→  const tabId = tab.id;
101→  const webviewLabel = tab.webviewLabel;
102→
103→  // --- Unmount guard ---
104→  useEffect(() => {
105→    mountedRef.current = true;
106→    return () => {
107→      mountedRef.current = false;
108→      cancelAnimationFrame(rafRef.current);
109→      if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
110→    };
111→  }, []);
112→
113→  // --- Create webview (lazy, on first navigation) ---
114→
115→  const createWebviewIfNeeded = useCallback(
116→    async (url: string) => {
117→      if (webviewCreatedRef.current) return;
118→
119→      // Set flag SYNCHRONOUSLY before await to prevent the auto-navigate
120→      // effect from re-firing during the async gap (onUpdateTab triggers
121→      // re-render → effect re-runs → ref still false → duplicate create).
122→      webviewCreatedRef.current = true;
123→
124→      const el = placeholderRef.current;
125→      if (!el) {
126→        webviewCreatedRef.current = false;
127→        return;
128→      }
129→
130→      const rect = el.getBoundingClientRect();
131→
132→      // Try to recall a parked view first (view parking keeps native views
133→      // alive across workspace switches). If the view exists, just reposition
134→      // and show it — no page reload, preserves scroll/form/login state.
135→      try {
136→        const exists = await native.browserViews.viewExists(webviewLabel);
137→        if (exists) {
138→          await native.browserViews.setBounds(webviewLabel, {
139→            x: rect.x,
140→            y: rect.y,
141→            width: Math.max(rect.width, 100),
142→            height: Math.max(rect.height, 100),
143→          });
144→          if (!mountedRef.current) return;
145→          setWebviewReady(true);
146→          setHasLoaded(true); // page is already loaded in the parked view
147→          // Re-sync native metadata for parked views — the page may have
148→          // navigated (redirects, SPA nav) while parked, so hydrated
149→          // URL/title could be stale. Fetch current values from the view.
150→          try {
151→            const currentUrl = await native.browserViews.evaluateWithResult(
152→              webviewLabel,
153→              "window.location.href",
154→              2000
155→            );
156→            const currentTitle = await native.browserViews.evaluateWithResult(
157→              webviewLabel,
158→              "document.title",
159→              2000
160→            );
161→            if (currentUrl) {
162→              onUpdateTab(tabId, {
163→                loading: false,
164→                currentUrl,
165→                url: currentUrl,
166→                title: currentTitle ?? tab.title,
167→              });
168→            } else {
169→              onUpdateTab(tabId, { loading: false });
170→            }
171→          } catch {
172→            onUpdateTab(tabId, { loading: false });
173→          }
174→          onAddLog(tabId, "info", `Recalled parked webview: ${webviewLabel}`);
175→          return;
176→        }
177→      } catch (err) {
178→        // viewExists failed — fall through to create (log for diagnostics)
179→        onAddLog(tabId, "warn", `viewExists check failed (will create fresh): ${err}`);
180→      }
181→
182→      try {
183→        await native.browserViews.create({
184→          label: webviewLabel,
185→          url,
186→          x: rect.x,
187→          y: rect.y,
188→          width: Math.max(rect.width, 100),
189→          height: Math.max(rect.height, 100),
190→          windowLabel: windowLabel ?? "main",
191→        });
192→
193→        // Guard: component may have unmounted during await
194→        if (!mountedRef.current) {
195→          native.browserViews.close(webviewLabel).catch(() => {});
196→          return;
197→        }
198→
199→        setWebviewReady(true);
200→
201→        // Start hidden — will show after first page load completes
202→        native.browserViews.hide(webviewLabel).catch(() => {});
203→
204→        onAddLog(tabId, "info", `Native webview created: ${webviewLabel}`);
205→      } catch (err) {
206→        // Reset flag so "Try Again" can re-attempt creation
207→        webviewCreatedRef.current = false;
208→        if (!mountedRef.current) return;
209→        onUpdateTab(tabId, { error: `Failed to create webview: ${err}`, loading: false });
210→        onAddLog(tabId, "error", `Webview creation failed: ${err}`);
211→      }
212→    },
213→    [webviewLabel, tabId, onUpdateTab, onAddLog, windowLabel]
214→  );
215→
216→  // --- Cleanup on unmount ---
217→  // Only hides the view — does NOT destroy it. Tab destruction is handled
218→  // explicitly by closeTab() in BrowserPanel. This enables view parking:
219→  // when switching workspaces, views are parked (hidden) and recalled later
220→  // without losing page state.
221→  useEffect(() => {
222→    const label = webviewLabel;
223→    return () => {
224→      if (webviewCreatedRef.current) {
225→        native.browserViews.hide(label).catch(() => {});
226→      }
227→    };
228→  }, [webviewLabel]);
229→
230→  // --- Auto-navigate hydrated tabs (restored from workspace persistence) ---
231→  // When a tab mounts with a persisted URL but no webview, auto-create it.
232→  // This handles workspace-switch where old webviews are destroyed and new
233→  // BrowserTab components mount with pre-filled URLs from the layout store.
234→  useEffect(() => {
235→    if (!visible || webviewCreatedRef.current || !tab.currentUrl) return;
236→    // Schedule async to avoid cascading renders from setState in effect
237→    const timer = setTimeout(() => {
238→      onUpdateTab(tabId, { loading: true });
239→      createWebviewIfNeeded(tab.currentUrl);
240→    }, 0);
241→    return () => clearTimeout(timer);
242→  }, [visible, tab.currentUrl, tabId, createWebviewIfNeeded, onUpdateTab]);
243→
244→  // --- Show/hide webview based on visibility + load state ---
245→  // Native webviews render ABOVE the DOM, so we hide them to reveal overlays.
246→  // Show only when: visible, loaded, and no initial error.
247→  useEffect(() => {
248→    if (!webviewReady) return;
249→
250→    if (visible && hasLoaded) {
251→      // Sync bounds before showing (layout may have changed while hidden)
252→      const el = placeholderRef.current;
253→      if (el) {
254→        const rect = el.getBoundingClientRect();
255→        native.browserViews
256→          .setBounds(webviewLabel, {
257→            x: rect.x,
258→            y: rect.y,
259→            width: rect.width,
260→            height: rect.height,
261→          })
262→          .then(() => native.browserViews.show(webviewLabel))
263→          .catch(() => {});
264→      } else {
265→        native.browserViews.show(webviewLabel).catch(() => {});
266→      }
267→    } else {
268→      native.browserViews.hide(webviewLabel).catch(() => {});
269→    }
270→  }, [visible, webviewReady, hasLoaded, webviewLabel]);
271→
272→  // --- Sync bounds with ResizeObserver (only when visible & loaded) ---
273→  useEffect(() => {
274→    if (!visible || !webviewReady || !hasLoaded) return;
275→
276→    const el = placeholderRef.current;
277→    if (!el) return;
278→
279→    const syncBounds = () => {
280→      cancelAnimationFrame(rafRef.current);
281→      rafRef.current = requestAnimationFrame(() => {
282→        const rect = el.getBoundingClientRect();
283→        if (rect.width === 0 || rect.height === 0) return;
284→        native.browserViews
285→          .setBounds(webviewLabel, {
286→            x: rect.x,
287→            y: rect.y,
288→            width: rect.width,
289→            height: rect.height,
290→          })
291→          .catch(() => {});
292→      });
293→    };
294→
295→    const observer = new ResizeObserver(syncBounds);
296→    observer.observe(el);
297→
298→    // Also sync on window resize (catches position-only changes)
299→    window.addEventListener("resize", syncBounds);
300→
301→    return () => {
302→      observer.disconnect();
303→      window.removeEventListener("resize", syncBounds);
304→      cancelAnimationFrame(rafRef.current);
305→    };
306→  }, [visible, webviewReady, hasLoaded, webviewLabel]);
307→
308→  // --- Re-sync bounds when mobile view toggles ---
309→  // The container CSS changes (w-full ↔ w-[390px] + mx-auto centering) change
310→  // BOTH the placeholder's size and its x-offset. ResizeObserver catches the
311→  // size change asynchronously, but it fires between layout and paint — racing
312→  // with effect-based sync can produce stale x-offsets.
313→  //
314→  // useLayoutEffect runs synchronously after React commits DOM but BEFORE the
315→  // browser paints. Calling getBoundingClientRect() here forces a synchronous
316→  // reflow that includes the newly committed CSS classes (w-[390px], mx-auto).
317→  // This guarantees correct width AND x-position in a single measurement — no
318→  // rAF, no race with ResizeObserver, no timing ambiguity.
319→  //
320→  // The hide → setBounds → show cycle ensures WKWebView's native compositor
321→  // actually repositions the view (setBounds on an already-visible native view
322→  // can be coalesced/ignored by the compositor in some environments).
323→  useLayoutEffect(() => {
324→    const changed = prevMobileViewRef.current !== mobileView;
325→    prevMobileViewRef.current = mobileView;
326→    if (!changed) return; // skip initial mount — visibility effect handles it
327→
328→    if (!visible || !webviewReady || !hasLoaded) return;
329→    const el = placeholderRef.current;
330→    if (!el || !webviewCreatedRef.current) return;
331→
332→    // Hide so the stale-position webview isn't visible during the transition.
333→    native.browserViews.hide(webviewLabel).catch(() => {});
334→
335→    // getBoundingClientRect() forces synchronous reflow — reads the post-toggle
336→    // layout including mx-auto centering offsets. No rAF needed because React
337→    // has already committed the DOM changes before useLayoutEffect runs.
338→    const rect = el.getBoundingClientRect();
339→    if (rect.width === 0 || rect.height === 0) return;
340→
341→    native.browserViews
342→      .setBounds(webviewLabel, {
343→        x: rect.x,
344→        y: rect.y,
345→        width: rect.width,
346→        height: rect.height,
347→      })
348→      .then(() => native.browserViews.show(webviewLabel))
349→      .catch(() => {});
350→  }, [mobileView, visible, webviewReady, hasLoaded, webviewLabel]);
351→
352→  // --- IPC event listeners (page load, title, SPA nav) ---
353→  useEffect(() => {
354→    const unlistenFns: Array<() => void> = [];
355→
356→    // Track whether did-fail-load fired for this navigation cycle.
357→    // Electron fires events: did-start-loading → did-fail-load → did-stop-loading.
358→    // Without this flag, "finished" (did-stop-loading) overwrites the error state.
359→    let didFailForCurrentNav = false;
360→
361→    // Page load events
362→    unlistenFns.push(
363→      native.events.on(BROWSER_PAGE_LOAD, (data) => {
364→        const { label, url, event: eventType } = data;
365→        if (label !== webviewLabel) return;
366→
367→        if (eventType === "started") {
368→          didFailForCurrentNav = false;
369→          // Clear any pending completion animation
370→          if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
371→          setCompletingLoad(false);
372→          // Reset injection flag — new page context destroys window.__deusVisuals
373→          automationInjectedRef.current = false;
374→          // Don't reset hasLoaded — once the first page has loaded, keep the
375→          // BrowserView visible. Subsequent navigations (redirects, SPA nav,
376→          // meta refresh) show the top loading bar, not the full-screen spinner.
377→          onUpdateTab(tabId, { loading: true });
378→        } else if (eventType === "finished") {
379→          // Skip if did-fail-load already fired — don't overwrite error state.
380→          // Electron always fires did-stop-loading after did-fail-load.
381→          if (didFailForCurrentNav) return;
382→          setHasLoaded(true);
383→          // Trigger completion animation (bar fills to 100% → fades)
384→          setCompletingLoad(true);
385→          completingTimerRef.current = setTimeout(() => setCompletingLoad(false), 500);
386→          onUpdateTab(tabId, { loading: false, currentUrl: url, error: null });
387→          onAddLog(tabId, "info", `Page loaded: ${url}`);
388→        } else if (eventType === "failed") {
389→          didFailForCurrentNav = true;
390→          // Clear loading bar animation
391→          if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
392→          setCompletingLoad(false);
393→          // Show error overlay instead of infinite spinner
394→          setHasLoaded(true);
395→          const errorDesc = data.error?.description ?? "Page failed to load";
396→          onUpdateTab(tabId, { loading: false, error: errorDesc });
397→          onAddLog(tabId, "error", `Page failed to load: ${errorDesc}`);
398→        }
399→      })
400→    );
401→
402→    // Title change events (regular, non-deus title changes)
403→    unlistenFns.push(
404→      native.events.on(BROWSER_TITLE_CHANGED, (data) => {
405→        const { label, title } = data;
406→        if (label !== webviewLabel) return;
407→        onUpdateTab(tabId, { title });
408→      })
409→    );
410→
411→    // Navigation events (did-navigate, did-navigate-in-page, pushState/replaceState)
412→    // Push to history so back/forward buttons work for all navigations.
413→    unlistenFns.push(
414→      native.events.on(BROWSER_URL_CHANGE, (data) => {
415→        const { label, url } = data;
416→        if (label !== webviewLabel) return;
417→
418→        // Suppress history push from programmatic back/forward navigation
419→        if (suppressHistoryPushRef.current) {
420→          suppressHistoryPushRef.current = false;
421→          onUpdateTab(tabId, { url, currentUrl: url, title: deriveTitleFromUrl(url) });
422→          return;
423→        }
424→
425→        const current = tabRef.current;
426→        // Skip duplicate URLs (e.g. hash-only changes that resolve to same URL)
427→        if (current.currentUrl === url) {
428→          onUpdateTab(tabId, { title: deriveTitleFromUrl(url) });
429→          return;
430→        }
431→        // Truncate forward history and append the new URL
432→        const newHistory = current.history.slice(0, current.historyIndex + 1);
433→        newHistory.push(url);
434→        onUpdateTab(tabId, {
435→          url,
436→          currentUrl: url,
437→          title: deriveTitleFromUrl(url),
438→          history: newHistory,
439→          historyIndex: newHistory.length - 1,
440→        });
441→      })
442→    );
443→
444→    // Console logs are drained via eval_browser_webview_with_result in the
445→    // "Periodic console drain" effect below.
446→    //
447→    // Inspect mode events are delivered SOLELY via buffer + drain polling
448→    // (eval_browser_webview_with_result every 200ms). We intentionally do NOT
449→    // use the title-channel for inspect events — it has two independent writers
450→    // (BROWSER_INIT_SCRIPT's SPA nav + inspect script) racing on document.title,
451→    // causing silent message loss via WKWebView's title-change coalescing.
452→
453→    return () => unlistenFns.forEach((fn) => fn());
454→  }, [webviewLabel, tabId, onUpdateTab, onAddLog]);
455→
456→  // --- Periodic console drain (only when visible and webview ready) ---
457→  // Uses eval_browser_webview_with_result (native completion handler) instead
458→  // of the old title-channel approach (drain_browser_console). The title-channel
459→  // suffers from WKWebView's title-change coalescing — when the 60ms restore
460→  // window overlaps with another title write (SPA nav, page itself), the
461→  // \x01CL: message is silently dropped and console logs are lost.
462→  //
463→  // The completion-handler path reads the log buffer directly and returns the
464→  // JSON via WKWebView's evaluateJavaScript callback, which is reliable.
465→  useEffect(() => {
466→    if (!visible || !webviewReady || !hasLoaded) return;
467→
468→    const CONSOLE_DRAIN_JS = `(function(){
469→      var b = window.__DEUS_LOGS__ || [];
470→      window.__DEUS_LOGS__ = [];
471→      return JSON.stringify(b);
472→    })()`;
473→
474→    // Track consecutive failures for diagnostic logging
475→    let consoleDrainFails = 0;
476→    // Guard against overlapping async drains — if invoke() takes longer than
477→    // the interval, skip until the previous call completes.
478→    let inFlight = false;
479→
480→    const interval = setInterval(async () => {
481→      if (inFlight) return;
482→      inFlight = true;
483→      try {
484→        const result = await native.browserViews.evaluateWithResult(
485→          webviewLabel,
486→          CONSOLE_DRAIN_JS,
487→          2000
488→        );
489→        // Reset on success
490→        consoleDrainFails = 0;
491→
492→        if (!result || result === "[]" || result === "undefined") return;
493→
494→        let logs: Array<{ l: string; m: string; t: number }>;
495→        try {
496→          logs = JSON.parse(result);
497→        } catch (parseErr) {
498→          console.error(
499→            "[BrowserTab] console drain: JSON.parse failed",
500→            parseErr,
501→            "raw:",
502→            result.slice(0, 200)
503→          );
504→          return;
505→        }
506→        for (const log of logs) {
507→          const level = match(log.l)
508→            .with("warn", () => "warn" as const)
509→            .with("error", () => "error" as const)
510→            .with("debug", () => "debug" as const)
511→            .otherwise(() => "info" as const);
512→          onAddLog(tabId, level, log.m);
513→        }
514→      } catch (err) {
515→        consoleDrainFails++;
516→        if (consoleDrainFails <= 3 || consoleDrainFails % 50 === 0) {
517→          console.warn(
518→            `[BrowserTab] console drain failed (${consoleDrainFails}x):`,
519→            getErrorMessage(err)
520→          );
521→        }
522→      } finally {
523→        inFlight = false;
524→      }
525→    }, CONSOLE_DRAIN_INTERVAL_MS);
526→
527→    return () => clearInterval(interval);
528→  }, [visible, webviewReady, hasLoaded, webviewLabel, tabId, onAddLog]);
529→
530→  // --- Periodic inspect event drain (only when selector is active) ---
531→  // Drains buffered events from the inject script via
532→  // eval_browser_webview_with_result (native completion handler).
533→  // This is the sole delivery path for inspect events — we do not use
534→  // the title-channel for inspect events (see file-level comment).
535→  useEffect(() => {
536→    if (!visible || !webviewReady || !hasLoaded || !tab.selectorActive) return;
537→
538→    // Flush stale events accumulated while tab was hidden — prevents
539→    // inserting unintended elements into chat on tab re-activation.
540→    native.browserViews
541→      .evaluateWithResult(webviewLabel, INSPECT_MODE_DRAIN_EVENTS, 2000)
542→      .catch(() => {});
543→
544→    // Track consecutive failures to avoid log spam (log first 3, then every 50th)
545→    let failCount = 0;
546→    // Guard against overlapping async drains — if invoke() takes longer than
547→    // the interval, skip until the previous call completes.
548→    let inFlight = false;
549→
550→    const interval = setInterval(async () => {
551→      if (inFlight) return;
552→      inFlight = true;
553→      try {
554→        const result = await native.browserViews.evaluateWithResult(
555→          webviewLabel,
556→          INSPECT_MODE_DRAIN_EVENTS,
557→          2000
558→        );
559→        // Reset fail counter on success
560→        failCount = 0;
561→
562→        if (!result || result === "[]" || result === "undefined") return;
563→
564→        let events: Array<{ type: string; data: Record<string, unknown> }>;
565→        try {
566→          events = JSON.parse(result);
567→        } catch (parseErr) {
568→          // JSON parse failure — log the raw result for debugging
569→          console.error(
570→            "[BrowserTab] inspect drain: JSON.parse failed",
571→            parseErr,
572→            "raw result:",
573→            result.slice(0, 200)
574→          );
575→          return;
576→        }
