600→          console.warn(`[BrowserTab] inspect drain failed (${failCount}x):`, getErrorMessage(err));
601→        }
602→      } finally {
603→        inFlight = false;
604→      }
605→    }, INSPECT_DRAIN_INTERVAL_MS);
606→
607→    return () => clearInterval(interval);
608→  }, [
609→    visible,
610→    webviewReady,
611→    hasLoaded,
612→    tab.selectorActive,
613→    webviewLabel,
614→    tabId,
615→    onUpdateTab,
616→    onAddLog,
617→  ]);
