692→      } catch (verifyErr) {
693→        onAddLog(tabId, "warn", `Inspect verification failed: ${getErrorMessage(verifyErr)}`);
694→        return;
695→      }
696→
697→      automationInjectedRef.current = true;
698→      onUpdateTab(tabId, { injected: true, injectionFailed: false });
699→      onAddLog(tabId, "info", "Automation scripts injected successfully");
