703→    }
704→  }, [tabId, webviewLabel, onUpdateTab, onAddLog]);
705→
706→  // Auto-inject on first page load — single call to injectAutomation().
707→  useEffect(() => {
708→    if (!hasLoaded || automationInjectedRef.current) return;
709→    injectAutomation();
710→  }, [hasLoaded, injectAutomation]);
711→
712→  const toggleElementSelector = useCallback(async () => {
713→    if (!webviewCreatedRef.current) return;
714→
715→    // Auto-inject if not yet injected
