733→  }, [webviewLabel, tabId, tab.selectorActive, injectAutomation, onUpdateTab, onAddLog]);
734→
735→  useImperativeHandle(
736→    ref,
737→    () => ({
738→      navigateToUrl,
739→      goBack,
740→      goForward,
741→      reload,
742→      injectAutomation,
743→      toggleElementSelector,
744→    }),
745→    [navigateToUrl, goBack, goForward, reload, injectAutomation, toggleElementSelector]
