 77→/** Load or create browser tabs for a workspace from persisted layout state */
 78→function loadWorkspaceTabs(wsId: string | null): { tabs: BrowserTabState[]; activeTabId: string } {
 79→  if (wsId) {
 80→    const layout = workspaceLayoutActions.getLayout(wsId);
 81→    if (layout.browserTabs.length > 0) {
 82→      const tabs = layout.browserTabs.map((pt) => hydratePersistedTab(pt));
 83→      const persisted = layout.activeBrowserTabId
 84→        ? layout.browserTabs.find((t) => t.id === layout.activeBrowserTabId)
 85→        : null;
 86→      return { tabs, activeTabId: persisted?.id ?? tabs[0].id };
 87→    }
 88→  }
 89→  const tab = createBrowserTab(wsId);
 90→  return { tabs: [tab], activeTabId: tab.id };
 91→}
