 93→/** Serialize tabs for persistence — only tabs with a loaded URL */
 94→function serializeTabs(tabs: BrowserTabState[]): PersistedBrowserTab[] {
 95→  return tabs
 96→    .filter((t) => t.currentUrl)
 97→    .map((t) => ({ id: t.id, url: t.currentUrl, title: t.title }));
 98→}
