  1→/**
  2→ * Browser View Preload Script
  3→ *
  4→ * Injected into BrowserView content pages (the agent browser).
  5→ *
  6→ * Responsibilities:
  7→ * 1. Console capture — forward to main process for the console panel
  8→ * 2. Dialog override — alert/confirm/prompt are non-blocking (prevents app freeze)
  9→ * 3. Keyboard shortcut routing — Cmd+R/L route back to IDE
 10→ *
 11→ * NOTE: WebAuthn and local-network-access polyfills are injected from the main
 12→ * process via view.webContents.executeJavaScript() on `dom-ready`, which targets
 13→ * the page's main world. The preload's webFrame.executeJavaScript() runs in the
 14→ * isolated world and cannot override page-visible APIs.
 15→ */
 16→
 17→import { ipcRenderer } from "electron";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Console capture — forward to main process
 21→// ---------------------------------------------------------------------------
 22→
 23→const originalConsole = {
 24→  log: console.log.bind(console),
 25→  warn: console.warn.bind(console),
 26→  error: console.error.bind(console),
 27→  info: console.info.bind(console),
 28→};
 29→
 30→function forwardConsole(level: string, args: unknown[]): void {
 31→  try {
 32→    const serialized = args.map((arg) => {
 33→      if (typeof arg === "string") return arg;
 34→      try {
 35→        return JSON.stringify(arg);
 36→      } catch {
 37→        return String(arg);
 38→      }
 39→    });
 40→    ipcRenderer.send("browser:console-message", { level, args: serialized });
 41→  } catch {
 42→    // Swallow errors — never break page JS
 43→  }
 44→}
 45→
 46→console.log = (...args: unknown[]) => {
 47→  originalConsole.log(...args);
 48→  forwardConsole("log", args);
 49→};
 50→
 51→console.warn = (...args: unknown[]) => {
 52→  originalConsole.warn(...args);
 53→  forwardConsole("warn", args);
 54→};
 55→
 56→console.error = (...args: unknown[]) => {
 57→  originalConsole.error(...args);
 58→  forwardConsole("error", args);
 59→};
 60→
 61→console.info = (...args: unknown[]) => {
 62→  originalConsole.info(...args);
 63→  forwardConsole("info", args);
 64→};
 65→
 66→// ---------------------------------------------------------------------------
 67→// Override blocking dialogs to be non-blocking
 68→// (intentional for agent automation — prevents app freeze from page dialogs)
 69→// ---------------------------------------------------------------------------
 70→
 71→window.alert = (message?: string) => {
 72→  originalConsole.log("[alert]", message);
 73→};
 74→
 75→window.confirm = (_message?: string) => {
 76→  originalConsole.log("[confirm]", _message);
 77→  return true; // Always confirm
 78→};
 79→
 80→window.prompt = (_message?: string, _defaultValue?: string) => {
 81→  originalConsole.log("[prompt]", _message);
 82→  return _defaultValue ?? null;
 83→};
 84→
 85→// ---------------------------------------------------------------------------
 86→// Keyboard shortcut routing
 87→//
 88→// When the BrowserView is focused, browser shortcuts (Cmd+R, Cmd+L, etc.)
 89→// would be consumed by the webview. Route them to the IDE instead so the
 90→// user gets expected behavior regardless of focus state.
 91→// ---------------------------------------------------------------------------
 92→
 93→window.addEventListener(
 94→  "keydown",
 95→  (e: KeyboardEvent) => {
 96→    const meta = e.metaKey || e.ctrlKey;
 97→    if (!meta) return;
 98→
 99→    switch (e.key) {
100→      case "r":
101→        // Cmd+R → reload the BrowserView (not the IDE)
102→        e.preventDefault();
103→        e.stopPropagation();
104→        ipcRenderer.send("browser:keyboard-shortcut", { shortcut: "reload" });
105→        break;
106→      case "l":
107→        // Cmd+L → focus the URL bar in our IDE
108→        e.preventDefault();
109→        e.stopPropagation();
110→        ipcRenderer.send("browser:keyboard-shortcut", { shortcut: "focus-url-bar" });
111→        break;
112→    }
113→  },
114→  true // capture phase — intercept before page handlers
115→);
