  1→// Thin wrapper around the agent-browser CLI.
  2→// Executes commands via child_process and parses JSON responses.
  3→// The daemon auto-starts on the first command per session and maintains
  4→// browser state (refs, cookies, DOM) across calls.
  5→
  6→import { execFile } from "child_process";
  7→import { dirname, join } from "path";
  8→
  9→export interface AgentBrowserResult {
 10→  success: boolean;
 11→  data: Record<string, unknown> | null;
 12→  error: string | null;
 13→}
 14→
 15→// Resolve the binary once at module load.
 16→// The npm package has a Node.js wrapper at bin/agent-browser.js that selects
 17→// the correct platform binary. We resolve it relative to the package directory
 18→// since the package has no "main" field (require.resolve would throw).
 19→// Note: agent-server is bundled to CJS, so require.resolve is available.
 20→const BINARY = (() => {
 21→  try {
 22→    const pkgDir = dirname(require.resolve("agent-browser/package.json"));
 23→    return join(pkgDir, "bin", "agent-browser.js");
 24→  } catch {
 25→    return "agent-browser"; // fallback to PATH
 26→  }
 27→})();
 28→
 29→const DEFAULT_TIMEOUT_MS = 35_000;
 30→
 31→/**
 32→ * Execute an agent-browser command for a given session.
 33→ * The daemon auto-starts on first invocation and stays alive
 34→ * for subsequent calls within the same session.
 35→ */
 36→export async function execAgentBrowser(
 37→  sessionId: string,
 38→  args: string[],
 39→  timeoutMs = DEFAULT_TIMEOUT_MS
 40→): Promise<AgentBrowserResult> {
 41→  const env = {
 42→    ...process.env,
 43→    AGENT_BROWSER_SESSION: sessionId,
 44→    AGENT_BROWSER_HEADED: "1",
 45→  };
 46→
 47→  return new Promise<AgentBrowserResult>((resolve, reject) => {
 48→    const child = execFile(
 49→      BINARY,
 50→      args,
 51→      { env, timeout: timeoutMs, maxBuffer: 10 * 1024 * 1024 },
 52→      (error, stdout, stderr) => {
 53→        // agent-browser prints JSON to stdout when invoked from daemon
 54→        const output = stdout.trim();
 55→
 56→        // Try to parse the last JSON line (agent-browser may print status lines before JSON)
 57→        if (output) {
 58→          const lines = output.split("\n");
 59→          for (let i = lines.length - 1; i >= 0; i--) {
 60→            const line = lines[i].trim();
 61→            if (line.startsWith("{")) {
 62→              try {
 63→                const parsed = JSON.parse(line);
 64→                resolve({
 65→                  success: parsed.success !== false,
 66→                  data: parsed.data ?? parsed,
 67→                  error: parsed.error ?? null,
 68→                });
 69→                return;
 70→              } catch {
 71→                continue;
 72→              }
 73→            }
 74→          }
 75→        }
 76→
 77→        // If the subprocess errored (timeout, non-zero exit, etc.), report failure
 78→        if (error) {
 79→          resolve({
 80→            success: false,
 81→            data: output ? { text: output } : null,
 82→            error: stderr || error.message,
 83→          });
 84→          return;
 85→        }
 86→
 87→        // No error and no output — success with no data
 88→        if (!output) {
 89→          resolve({ success: true, data: null, error: null });
 90→          return;
 91→        }
 92→
 93→        // No JSON found — treat raw output as text data
 94→        resolve({ success: true, data: { text: output }, error: null });
 95→      }
 96→    );
 97→
 98→    // Prevent zombie processes
 99→    child.on("error", (err) => reject(err));
100→  });
101→}
102→
103→/**
104→ * Execute an agent-browser command and return the snapshot text (accessibility tree).
105→ * Used after actions that return a snapshot (click, type, navigate, scroll, etc.)
106→ */
107→export async function execWithSnapshot(
108→  sessionId: string,
109→  args: string[],
110→  timeoutMs?: number
111→): Promise<{ snapshot?: string; url?: string; title?: string; error?: string }> {
112→  try {
113→    const result = await execAgentBrowser(sessionId, args, timeoutMs);
114→    if (!result.success) {
115→      return { error: result.error || "Unknown error" };
116→    }
117→
118→    // After an action, take a snapshot to return to the agent
119→    const snapResult = await execAgentBrowser(sessionId, ["snapshot", "--json"], timeoutMs);
120→    if (!snapResult.success) {
121→      return { error: `Action succeeded but snapshot failed: ${snapResult.error || "unknown"}` };
122→    }
123→    const snapshot = (snapResult.data?.snapshot as string) || (snapResult.data?.text as string);
124→
125→    // Get current URL and title (best-effort, don't fail if these error)
126→    const urlResult = await execAgentBrowser(sessionId, ["get", "url", "--json"]).catch(() => null);
127→    const titleResult = await execAgentBrowser(sessionId, ["get", "title", "--json"]).catch(
128→      () => null
129→    );
130→
131→    return {
132→      snapshot,
133→      url: (urlResult?.data?.url as string) || (urlResult?.data?.text as string),
134→      title: (titleResult?.data?.title as string) || (titleResult?.data?.text as string),
135→    };
136→  } catch (err: unknown) {
137→    return { error: err instanceof Error ? err.message : String(err) };
138→  }
139→}
