142→ * Get a snapshot with URL and title in one go.
143→ * Used by BrowserSnapshot tool.
144→ */
145→export async function getSnapshot(
146→  sessionId: string,
147→  timeoutMs?: number
148→): Promise<{ snapshot?: string; url?: string; title?: string; error?: string }> {
