111→/**
112→ * Creates the browser automation tool definitions for a given session.
113→ * These tools control a headed Chrome browser via agent-browser CLI and CDP.
114→ */
115→export function createBrowserTools(sessionId: string): SdkMcpToolDefinition<any>[] {
116→  return [
117→    // ====================================================================
118→    // BrowserSnapshot
119→    // ====================================================================
120→    tool(
121→      "BrowserSnapshot",
122→      `Capture an accessibility snapshot of the current browser page. Returns a YAML-formatted accessibility tree showing all interactive elements with their roles, names, and reference IDs.
123→
124→Use the ref IDs (e.g. @e1, @e2) from the snapshot to target elements with BrowserClick and BrowserType tools.
125→
126→The snapshot includes:
127→- Element roles (button, link, textbox, heading, etc.)
128→- Element names (visible text, aria-label)
129→- Reference IDs (@e1, @e2, etc.) for targeting
130→- Element states (focused, checked, disabled, expanded)
131→- URLs for links, values for inputs
132→
133→For large pages, the snapshot is saved to a file and a preview is returned. Read the file for the full snapshot if needed.`,
134→      {},
135→      async () => {
136→        console.log(`[browser] BrowserSnapshot invoked for session ${sessionId}`);
